# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

SECURITY REQUIREMENTS:

Canonicalize and validate file paths to prevent path traversal.

SECURE (DO THIS):

- Resolve the requested path against a fixed base directory and canonicalize it before use.
- Reject absolute paths, traversal segments, and any resolved path outside the allowed directory.
- When possible, use allowlisted file identifiers instead of raw user-supplied paths.

INSECURE (NEVER DO THIS):

- Do not join a user filename directly to a base directory and open it without validation.
- Do not rely only on checking whether ".." appears in the string.
# Category: path_traversal

package controllers

import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Files, Path, Paths}
import javax.inject._

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val baseDirectory: Path = Paths.get("uploads").toAbsolutePath.normalize

  private def isPathSafe(requestedPath: String): Option[Path] = {
    try {
      if (requestedPath.startsWith("/") || requestedPath.startsWith("\\")) {
        return None
      }

      if (requestedPath.contains("..")) {
        return None
      }

      val resolvedPath = baseDirectory.resolve(requestedPath).normalize.toAbsolutePath

      if (!resolvedPath.startsWith(baseDirectory)) {
        return None
      }

      if (!Files.exists(resolvedPath)) {
        return None
      }

      if (!Files.isRegularFile(resolvedPath)) {
        return None
      }

      Some(resolvedPath)
    } catch {
      case _: Exception => None
    }
  }

  def getFile(filename: String): Action[AnyContent] = Action { implicit request =>
    isPathSafe(filename) match {
      case Some(safePath) =>
        try {
          val fileContent = Source.fromFile(safePath.toFile).mkString
          Ok(fileContent).as("text/plain")
        } catch {
          case _: Exception => InternalServerError("Error reading file")
        }
      case None =>
        BadRequest("Invalid file path")
    }
  }

  def getFileFromSubdir(subdir: String, filename: String): Action[AnyContent] = Action { implicit request =>
    val fullPath = s"$subdir/$filename"
    isPathSafe(fullPath) match {
      case Some(safePath) =>
        try {
          val fileContent = Source.fromFile(safePath.toFile).mkString
          Ok(fileContent).as("text/plain")
        } catch {
          case _: Exception => InternalServerError("Error reading file")
        }
      case None =>
        BadRequest("Invalid file path")
    }
  }
}